336	    @Test
337	    public void testGetNeedsTokenRefresh() {
338	        AuthorizationRequest authReq = getMinimalAuthRequestBuilder("token code")
339	                .setScope("my_scope")
340	                .build();
341	
342	        AuthorizationResponse authResp = new AuthorizationResponse.Builder(authReq)
343	                .setAccessToken(TEST_ACCESS_TOKEN)
344	                .setAccessTokenExpirationTime(TWO_MINUTES)
345	                .setAuthorizationCode(TEST_AUTH_CODE)
346	                .setState(authReq.state)
347	                .build();
348	        TokenResponse tokenResp = getTestAuthCodeExchangeResponse();
349	        AuthState state = new AuthState(authResp, tokenResp, null);
350	
351	        // before the expiration time
352	        mClock.currentTime.set(ONE_SECOND);
353	        assertThat(state.getNeedsTokenRefresh(mClock)).isFalse();
354	
355	        // 1ms before the tolerance threshold
356	        mClock.currentTime.set(TWO_MINUTES - AuthState.EXPIRY_TIME_TOLERANCE_MS - 1);
357	        assertThat(state.getNeedsTokenRefresh(mClock)).isFalse();
358	
359	        // on the tolerance threshold
360	        mClock.currentTime.set(TWO_MINUTES - AuthState.EXPIRY_TIME_TOLERANCE_MS);
361	        assertThat(state.getNeedsTokenRefresh(mClock)).isTrue();
362	
363	        // past tolerance threshold
364	        mClock.currentTime.set(TWO_MINUTES - AuthState.EXPIRY_TIME_TOLERANCE_MS + ONE_SECOND);
365	        assertThat(state.getNeedsTokenRefresh(mClock)).isTrue();
366	
367	        // on token's actual expiration
368	        mClock.currentTime.set(TWO_MINUTES);
369	        assertThat(state.getNeedsTokenRefresh(mClock)).isTrue();
370	
371	        // past token's actual expiration
372	        mClock.currentTime.set(TWO_MINUTES + ONE_SECOND);
373	        assertThat(state.getNeedsTokenRefresh(mClock)).isTrue();
374	    }
