506	    @Test
507	    public void testPerformActionWithFreshToken_afterTokenExpiration_multipleActions() {
508	        AuthorizationRequest authReq = getMinimalAuthRequestBuilder("id_token token code")
509	            .setScope("my_scope")
510	            .build();
511	
512	        AuthorizationResponse authResp = new AuthorizationResponse.Builder(authReq)
513	            .setAccessToken(TEST_ACCESS_TOKEN)
