517	            .setState(authReq.state)
518	            .build();
519	        TokenResponse tokenResp = getTestAuthCodeExchangeResponse();
520	        AuthState state = new AuthState(authResp, tokenResp, null);
521	
522	        AuthorizationService service = mock(AuthorizationService.class);
523	        AuthState.AuthStateAction action = mock(AuthState.AuthStateAction.class);
524	
525	        // at this point in time, the access token will be considered to be expired
526	        mClock.currentTime.set(TWO_MINUTES - AuthState.EXPIRY_TIME_TOLERANCE_MS + ONE_SECOND);
527	        state.performActionWithFreshTokens(
528	            service,
529	            NoClientAuthentication.INSTANCE,
530	            Collections.<String, String>emptyMap(),
531	            mClock,
532	            action);
533	        state.performActionWithFreshTokens(
534	            service,
535	            NoClientAuthentication.INSTANCE,
536	            Collections.<String, String>emptyMap(),
537	            mClock,
538	            action);
539	
540	        // as the access token has expired, we expect a token refresh request
541	        ArgumentCaptor<TokenRequest> requestCaptor = ArgumentCaptor.forClass(TokenRequest.class);
542	        ArgumentCaptor<AuthorizationService.TokenResponseCallback> callbackCaptor =
543	            ArgumentCaptor.forClass(AuthorizationService.TokenResponseCallback.class);
544	
545	        verify(service, times(1)).performTokenRequest(
546	            requestCaptor.capture(),
547	            any(ClientAuthentication.class),
548	            callbackCaptor.capture());
549	
550	        assertThat(requestCaptor.getValue().refreshToken).isEqualTo(tokenResp.refreshToken);
551	
552	        // the action should not be executed until after the token refresh completes
553	        verifyNoInteractions(action);
554	
555	        String freshRefreshToken = "fresh_refresh_token";
556	        String freshAccessToken = "fresh_access_token";
557	        String freshIdToken = "fresh.id.token";
558	        Long freshExpirationTime = mClock.currentTime.get() + TWO_MINUTES;
559	
560	        // simulate success on the token request, with fresh tokens in the result
561	        TokenResponse freshResponse = new TokenResponse.Builder(requestCaptor.getValue())
562	            .setTokenType(TokenResponse.TOKEN_TYPE_BEARER)
563	            .setAccessToken(freshAccessToken)
564	            .setAccessTokenExpirationTime(freshExpirationTime)
565	            .setIdToken(freshIdToken)
566	            .setRefreshToken(freshRefreshToken)
567	            .build();
568	
569	        callbackCaptor.getValue().onTokenRequestCompleted(freshResponse, null);
570	        // the action should be invoked in response to the token request completion
571	        verify(action, times(2)).execute(
572	            eq(freshAccessToken),
573	            eq(freshIdToken),
574	            ArgumentMatchers.<AuthorizationException>isNull());
