349	        if (mNeedsTokenRefreshOverride) {
350	            return true;
351	        }
352	
353	        if (getAccessTokenExpirationTime() == null) {
354	            // if there is no expiration but we have an access token, it is assumed
355	            // to never expire.
356	            return getAccessToken() == null;
357	        }
