        assertThat(state.getNeedsTokenRefresh(mClock)).isTrue();

        // on token's actual expiration
        mClock.currentTime.set(TWO_MINUTES);
        assertThat(state.getNeedsTokenRefresh(mClock)).isTrue();

        // past token's actual expiration
        mClock.currentTime.set(TWO_MINUTES + ONE_SECOND);
