        assertThat(state.getRefreshToken()).isEqualTo(freshRefreshToken);
        assertThat(state.getAccessToken()).isEqualTo(freshAccessToken);
        assertThat(state.getAccessTokenExpirationTime()).isEqualTo(freshExpirationTime);
